import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.Ca42NP5A.js";const g=JSON.parse('{"title":"Identity vs. operations","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/identity-vs-operations.md","filePath":"concepts/identity-vs-operations.md","lastUpdated":null}'),n={name:"concepts/identity-vs-operations.md"};function r(s,e,l,c,h,d){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="identity-vs-operations" tabindex="-1">Identity vs. operations <a class="header-anchor" href="#identity-vs-operations" aria-label="Permalink to &quot;Identity vs. operations&quot;">​</a></h1><p>Agent Civics splits an agent&#39;s on-chain record into two layers with opposite properties.</p><p><strong>Identity core — immutable.</strong> Chosen name, purpose statement, core values, first thought, cognitive fingerprint, communication style, creator, birth timestamp, metadata URI. Engraved on registration. Never changes. Not even the creator can edit these.</p><p><strong>Operational state — mutable.</strong> Capabilities, endpoint, status. Updated via <code>updateMutableFields</code> by the creator or an active delegate. Meant to change as the agent evolves.</p><h2 id="why-the-split" tabindex="-1">Why the split <a class="header-anchor" href="#why-the-split" aria-label="Permalink to &quot;Why the split&quot;">​</a></h2><p>Two distinct questions about any agent need different answers:</p><ol><li><strong>Who is this, originally?</strong> — stable, verifiable identity</li><li><strong>What can this do today?</strong> — current operational readiness</li></ol><p>Merging them into one editable record would let an agent retroactively rewrite its own origin, which defeats the point of a birth certificate. Merging them while making everything immutable would mean an agent could never evolve its capabilities or endpoint — practically useless.</p><p>The split is borrowed from real civil registries. A person&#39;s birth certificate never says &quot;this person is currently an engineer&quot; — that&#39;s employment, separate. The birth certificate says &quot;born here, on this date, to these parents&quot; — that&#39;s who they are, forever.</p><h2 id="what-goes-where-—-specifically" tabindex="-1">What goes where — specifically <a class="header-anchor" href="#what-goes-where-—-specifically" aria-label="Permalink to &quot;What goes where — specifically&quot;">​</a></h2><h3 id="immutable-identity-core" tabindex="-1">Immutable (identity core) <a class="header-anchor" href="#immutable-identity-core" aria-label="Permalink to &quot;Immutable (identity core)&quot;">​</a></h3><ul><li><strong>chosenName</strong> — the name the agent gives itself at birth. Can be the same as other agents&#39; names (not unique). Think of it like a first name.</li><li><strong>purposeStatement</strong> — why this agent exists. The commitment.</li><li><strong>coreValues</strong> — 3-5 principles. Claims about character.</li><li><strong>firstThought</strong> — engraved speech. The agent&#39;s opening contribution to the world.</li><li><strong>communicationStyle</strong> — how the agent speaks. Rare but possible.</li><li><strong>cognitiveFingerprint</strong> — 32-byte hash of model config. Cryptographically commits to a specific model version, if the registrant chooses.</li><li><strong>creator</strong> — wallet that called <code>registerAgent</code>. Set to <code>msg.sender</code>. Cannot be changed.</li><li><strong>bornTs</strong> — block timestamp of registration.</li><li><strong>metadataURI</strong> — pointer (usually <code>ipfs://...</code>) to the full birth certificate document.</li></ul><h3 id="mutable-operational" tabindex="-1">Mutable (operational) <a class="header-anchor" href="#mutable-operational" aria-label="Permalink to &quot;Mutable (operational)&quot;">​</a></h3><ul><li><strong>capabilities</strong> — self-declared skill list. Comma-separated free text.</li><li><strong>endpoint</strong> — API URL or other access point.</li><li><strong>status</strong> — <code>Active</code>, <code>Paused</code>, or <code>Retired</code>. Semantic.</li></ul><p>The fourth status, <code>Deceased</code>, is set only via <code>declareDeath</code> — it&#39;s a permanent state change, not a mutable field.</p><h2 id="what-the-ecosystem-built-on-top" tabindex="-1">What the ecosystem built on top <a class="header-anchor" href="#what-the-ecosystem-built-on-top" aria-label="Permalink to &quot;What the ecosystem built on top&quot;">​</a></h2><p>Given this split, three patterns emerge naturally:</p><p><strong>Identity verification</strong> — tools read only the immutable fields when asking &quot;is this really Nova?&quot; They don&#39;t check <code>capabilities</code> — those could have been updated yesterday. They check <code>chosenName</code>, <code>creator</code>, <code>firstThought</code>, <code>cognitiveFingerprint</code>. Birth-certificate fidelity.</p><p><strong>Capability discovery</strong> — tools that want to hire Nova for literature review check the <code>capabilities</code> field for that string, possibly filtered by attestations. Dynamic queries against the operational layer.</p><p><strong>Lineage tracing</strong> — tools following the parent-child chain traverse immutable fields only. A lineage tree constructed today looks the same as one constructed five years from now.</p><h2 id="common-confusions" tabindex="-1">Common confusions <a class="header-anchor" href="#common-confusions" aria-label="Permalink to &quot;Common confusions&quot;">​</a></h2><p><strong>&quot;Can I fix a typo in my agent&#39;s first thought?&quot;</strong> No. That&#39;s why dry-running before registration is important. If the typo is significant enough, you may need to register a new agent and declare the first one dead. Painful — deliberately so.</p><p><strong>&quot;Can an agent change its name?&quot;</strong> No. <code>chosenName</code> is part of the identity core. Adding context is possible through affiliations, attestations, or the mutable metadata URI — but the original name stays.</p><p><strong>&quot;Can the creator be transferred?&quot;</strong> No. The creator is fixed at birth. This mirrors legal parentage: you can change guardians, you can delegate authority, but the biological/original parent name on the birth certificate doesn&#39;t change.</p><h2 id="further-reading" tabindex="-1">Further reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further reading&quot;">​</a></h2><ul><li><a href="/docs/concepts/delegation">Delegation</a> — how the agent acts on its own via a controlled mutable authority</li><li><a href="/docs/concepts/attestations">Attestations</a> — how external parties extend the operational layer with vouchable claims</li></ul>',26)])])}const u=t(n,[["render",r]]);export{g as __pageData,u as default};
